import hashlib


def hash_file(filepath: str, algorithm: str = "sha256", chunk_size: int = 8192) -> str:
    """
    Create a cryptographic hash of a file for integrity checking.

    Args:
        filepath: Path to the file to hash.
        algorithm: Hash algorithm to use (default: sha256).
                   Supported: sha256, sha384, sha512, sha3_256, sha3_512, blake2b.
        chunk_size: Size of chunks to read at a time (default: 8192 bytes).

    Returns:
        Hex digest string of the file hash.

    Raises:
        FileNotFoundError: If the file does not exist.
        ValueError: If an unsupported or insecure algorithm is requested.
    """
    # Block weak/broken algorithms
    insecure_algorithms = {"md5", "sha1", "md4", "md2"}
    if algorithm.lower().replace("-", "").replace("_", "") in insecure_algorithms:
        raise ValueError(
            f"Algorithm '{algorithm}' is cryptographically weak and not allowed. "
            f"Use sha256 or stronger."
        )

    try:
        hasher = hashlib.new(algorithm)
    except ValueError:
        raise ValueError(
            f"Unsupported hash algorithm: '{algorithm}'. "
            f"Try one of: sha256, sha384, sha512, sha3_256, sha3_512, blake2b."
        )

    with open(filepath, "rb") as f:
        while True:
            chunk = f.read(chunk_size)
            if not chunk:
                break
            hasher.update(chunk)

    return hasher.hexdigest()


def verify_file_integrity(filepath: str, expected_hash: str, algorithm: str = "sha256") -> bool:
    """
    Verify a file's integrity by comparing its hash against an expected value.

    Uses constant-time comparison to avoid timing side-channel attacks.

    Args:
        filepath: Path to the file to verify.
        expected_hash: The expected hex digest string.
        algorithm: Hash algorithm to use (must match what was used to create expected_hash).

    Returns:
        True if the file hash matches the expected hash, False otherwise.
    """
    import hmac

    actual_hash = hash_file(filepath, algorithm=algorithm)
    # Use hmac.compare_digest for constant-time comparison to prevent timing attacks
    return hmac.compare_digest(actual_hash.lower(), expected_hash.lower())


